from pathlib import Path
root=Path('.gsd/milestones/M001/slices')
for sdir in sorted(root.glob('S[0-9][0-9]')):
    sid=sdir.name
    print(f'## {sid}')
    for kind in ['SUMMARY','UAT']:
        p=sdir/f'{sid}-{kind}.md'
        if not p.exists():
            print(f'{kind}: MISSING')
            continue
        text=p.read_text(encoding='utf-8', errors='replace')
        lines=text.splitlines()
        # title and bold summary
        title=next((l for l in lines if l.startswith('# ')), '')
        bold=next((l for l in lines if l.startswith('**') and l.endswith('**')), '')
        print(f'{kind}: {title} {bold}')
        # print provides block for summaries
        if kind=='SUMMARY':
            in_provides=False; provides=[]
            for l in lines:
                if l.startswith('provides:'):
                    in_provides=True; continue
                if in_provides:
                    if l.startswith('  - '): provides.append(l[4:])
                    elif l and not l.startswith(' '): break
            if provides:
                print('Provides: ' + ' | '.join(provides[:5]))
            # verification section first non-empty paragraphs until next heading (max 8 lines)
            for idx,l in enumerate(lines):
                if l.strip()=='## Verification':
                    block=[]
                    for m in lines[idx+1:]:
                        if m.startswith('## '): break
                        if m.strip(): block.append(m.strip())
                    print('Verification: ' + ' '.join(block[:4])[:900])
                    break
            # requirements validated IDs
            for idx,l in enumerate(lines):
                if l.strip()=='## Requirements Validated':
                    vals=[]
                    for m in lines[idx+1:]:
                        if m.startswith('## '): break
                        if m.startswith('- '): vals.append(m[2:])
                    if vals: print('Validated: ' + ' | '.join(vals[:8])[:1000])
                    break
        else:
            # UAT status and acceptance rows
            status=[l.strip() for l in lines if 'Execution status:' in l or 'UAT type:' in l]
            if status: print('Status: ' + ' | '.join(status))
            rows=[]
            for l in lines:
                if l.startswith('|') and not set(l.replace('|','').replace('-','').replace(':','').strip())==set():
                    if '---' in l: continue
                    if any(h in l for h in ['Area |','Scenario |','Step |','Check |']): continue
                    rows.append(l.strip())
            if rows: print('UAT rows: ' + ' || '.join(rows[:6])[:1200])
    print()

