{"runtime":"python3","purpose":"Audit M001 slice summary, assessment, and UAT artifacts","script":"from pathlib import Path
root = Path('.gsd/milestones/M001/slices')
if not root.exists():
    print('ERROR: slices directory missing')
    raise SystemExit(1)
rows=[]
missing=[]
for p in sorted(root.glob('S*')):
    if not p.is_dir():
        continue
    sid=p.name
    summary=p/f'{sid}-SUMMARY.md'
    assess=p/f'{sid}-ASSESSMENT.md'
    uat=p/f'{sid}-UAT.md'
    def status(path):
        if not path.exists():
            missing.append(str(path)); return 'missing'
        text=path.read_text(encoding='utf-8', errors='replace')
        if path.name.endswith('ASSESSMENT.md'):
            lower=text.lower()
            if 'verdict: pass' in lower or 'verdict: passed' in lower or 'assessment verdict: pass' in lower or 'pass' in lower:
                return 'present/pass-signal'
            return 'present/no-pass-signal'
        return 'present'
    rows.append((sid,status(summary),status(assess),status(uat)))
print('slice | summary | assessment | uat')
for r in rows:
    print(' | '.join(r))
print(f'total_slices={len(rows)} missing={len(missing)}')
if missing:
    print('missing_paths=' + ';'.join(missing))
    raise SystemExit(1)"}

